using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — services are injected through the constructor.
/// </summary>
[McpServerToolType]
public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get the current weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name, e.g. 'Seattle' or 'London'")] string city,
        [Description("Number of forecast days (1-5)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching {Days}-day forecast for {City}", days, city);

        days = Math.Clamp(days, 1, 5);
        var response = await httpClient.GetAsync(
            $"forecast.json?q={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }

    [McpServerTool(ReadOnly = true), Description("Search for matching city or location names.")]
    public async Task<string> SearchLocations(
        [Description("Search query — partial city name or zip code")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching locations: {Query}", query);

        var response = await httpClient.GetAsync(
            $"search.json?q={Uri.EscapeDataString(query)}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }

    [McpServerTool(ReadOnly = true), Description("Get current conditions for a city (temp, wind, humidity).")]
    public async Task<string> GetCurrentConditions(
        [Description("City name or coordinates")] string location,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching current conditions for {Location}", location);

        var response = await httpClient.GetAsync(
            $"current.json?q={Uri.EscapeDataString(location)}",
            cancellationToken);

        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }
}

